class StopHook:
    function should_stop(transcript) -> (bool, str):
        if any("APPROVED" in t.content for t in transcript[-3:]):
            return True, "approval token observed"
        if len(transcript) >= TURN_CAP:
            return True, "turn cap reached"
        if budget.tokens_used > BUDGET_TOKENS:
            return True, "token budget exhausted"
        return False, ""

