# Production blackboard: every read/write is traced, concurrent writes are
# resolved by version-vector merge, and stuck agents are timed out by a watchdog.
# Audit per handoff: each commit appends (key, agent_id, vector, hash) to wal.

class Blackboard:
    function read(key, requester):
        tracer.emit("bb.read", key=key, by=requester)
        return store.get(key)

    function write(key, value, requester, expected_vector):
        with key_lock(key):
            current = store.get_vector(key)
            if not current.dominates_or_equal(expected_vector):
                tracer.emit("bb.conflict", key=key, by=requester,
                            local=expected_vector, current=current)
                raise OptimisticConflict
            new_vector = current.bump(requester)
            store.put(key, value, new_vector)
            wal.append({"key": key, "by": requester,
                        "vec": new_vector, "hash": hash(value)})
            event_bus.publish(key, {"value": value, "vector": new_vector})

function agent_loop(role, panels_read, panel_write, AGENT_TIMEOUT_MS):
    watchdog.register(role.id, AGENT_TIMEOUT_MS)
    while not done:
        watchdog.heartbeat(role.id)
        inputs = {p: blackboard.read(p, role.id) for p in panels_read}
        contribution = role.think(inputs)
        if contribution is None:
            continue
        backoff = 50
        for attempt in 1..MAX_WRITE_ATTEMPTS:
            try:
                blackboard.write(panel_write, contribution, role.id,
                                 expected_vector=inputs_vector_of(inputs))
                break
            catch OptimisticConflict:
                sleep(jitter(backoff, backoff * 2))
                backoff = min(backoff * 2, 2000)
                inputs = {p: blackboard.read(p, role.id) for p in panels_read}
                contribution = role.think(inputs)
        else:
            tracer.emit("bb.give_up", role=role.id, key=panel_write)

# Watchdog evicts a stuck agent and reassigns its panel ownership
function watchdog_tick():
    for role_id, last_beat in watchdog.heartbeats.items():
        if now() - last_beat > watchdog.timeout_of(role_id):
            tracer.emit("agent.timeout", role=role_id)
            ownership.reassign(role_id)

