# Coordination seam: the swarm's handoff protocol carries work between cells
# WITHIN the neighborhood; nothing reads outside the radius.

grid = Grid(width=W, height=H)
for (x, y) in grid.cells:
    grid[x, y] = Cell(
        state=initial_state(x, y),
        radius=K,
        rule=rule_with_handoff,
        capabilities=capabilities_at(x, y),                # e.g. {"watch","act"}
    )

function rule_with_handoff(self, neighbors):
    # local condition detected — but THIS cell is not the right specialist
    if condition_fired(self.state, neighbors) and "act" not in self.capabilities:
        for n in neighbors:
            if "act" in n.capabilities:
                reply = n.accept_handoff(                  # decentralized-swarm-handoff
                    task={"trigger": self.state, "context": neighbors},
                    from_peer=self.id,
                )
                if reply.verdict == "accept":
                    handoff_log.append({"from": self.id, "to": n.id,
                                        "token": reply.handoff_token})
                    return self.state                       # we passed it on
        # no nearby specialist accepted — degrade gracefully, keep state
        return self.state
    # ordinary local update
    return default_local_update(self.state, neighbors)

function step(grid):
    next_grid = grid.blank_copy()
    for (x, y), cell in grid.items():
        neighbors = grid.neighborhood(x, y, radius=cell.radius)
        next_grid[x, y] = cell.with_state(cell.rule(cell, neighbors))
    return next_grid

# Why this works: keeping the swarm-handoff protocol scoped to the neighborhood
# preserves the locality invariant — no peer query ever escapes the radius —
# while letting specialised cells take over work that a generic cell detected.
# Related: see `decentralized-swarm-handoff`, `swarm`, `actor-model-agents`.

function answer(instruction, instructor, depth=0):
    plan = assistant.analyse(instruction)

    if plan.is_missing_deciding_context() and depth < MAX_REVERSALS:
        # role reversal: assistant becomes the asker
        question = assistant.formulate_one_question(plan.gap)
        clarification = instructor.answer(question)

        # recurse with augmented instruction, capped by depth
        return answer(
            instruction=instruction + clarification,
            instructor=instructor,
            depth=depth + 1,
        )

    # either no gap, or depth budget reached; commit to an answer
    return assistant.produce_conclusion(instruction, plan)

