function invoke_open_network(target_did, intent, payload):
    did_doc      = resolve_did(target_did)    # DID:web / DID:key / etc.
    descriptor   = fetch(did_doc.descriptor_url)
    signature    = fetch(did_doc.signature_url)

    if not verify_signature(descriptor, signature, did_doc.keys):
        return abort("signature verification failed")

    capability = find_capability(descriptor, intent)
    if capability is None:
        return abort("capability not advertised")

    # only NOW honour any claim: identity is cryptographic, not in-band
    return call_protocol(capability.endpoint, payload)

