# Every peer exposes the same handoff endpoint
function accept_handoff(self, task, from_peer):
    if self.capacity_used > CAPACITY_HIGH_WATER:
        return {"verdict": "defer", "retry_after_ms": 5000}     # back-pressure
    if not capability_match(self.capabilities, task.required_tags):
        return {"verdict": "decline", "reason": "capability mismatch"}
    handoff_log.append({"to": self.id, "from": from_peer, "task": task.id})
    self.enqueue(task)
    return {"verdict": "accept", "handoff_token": new_token()}

# Initiator side — addresses peers by CAPABILITY TAG, not by identity
function initiate_handoff(task, capability_tag, exclude=set()):
    candidates = registry.peers_with(capability_tag) - exclude
    for peer in rank_by_recent_latency(candidates):
        reply = peer.accept_handoff(task, from_peer=self.id)
        match reply.verdict:
            case "accept":
                return reply.handoff_token
            case "defer":
                schedule_retry(peer, reply.retry_after_ms); continue
            case "decline":
                exclude.add(peer); continue
    return escalate("no peer accepted — capability shortage for " + capability_tag)

# Trace reconstruction: every accept appends to per-peer handoff_log;
# the full chain for a task is the union of logs filtered by task.id.

# Why this works: explicit accept / defer / decline + capability addressing
# means no central router is required and the swarm still scales, while the
# per-peer handoff_log keeps the trace of who handed work to whom fully
# reconstructable — something implicit-shared-memory handoffs cannot give.
# Related: see `swarm`, `decentralized-agent-network`, `handoff`.

# Coordination seam: the handoff token is the unit of accountability; the
# reputation store reads completion outcomes and feeds back into peer ranking.

rep = ReputationStore()
open_handoffs = {}                              # token -> {from, to, at}

function initiate_handoff(task, capability_tag):
    candidates = registry.peers_with(capability_tag)
    # Rank by reputation FIRST, capacity second — composition seam
    ranked = sort(candidates,
                  key=lambda p: (-rep.get(p.id), p.load_pct()))
    for peer in ranked:
        reply = peer.accept_handoff(task, from_peer=self.id)
        if reply.verdict == "accept":
            open_handoffs[reply.handoff_token] = {
                "from": self.id, "to": peer.id, "task": task.id, "at": now()}
            return reply.handoff_token
        if reply.verdict == "defer":
            schedule_retry(peer, reply.retry_after_ms)
    return escalate("no peer accepted", capability_tag)

# Closing-the-loop side: when the accepting peer reports completion, its
# reputation goes up; on failure / no-report-within-deadline, it goes down.
function on_task_completion(token, outcome):
    h = open_handoffs.pop(token)
    delta = +1 if outcome.success else -2                  # asymmetric penalty
    rep.update(agent=h.to, delta=delta, decay=DECAY_RATE)
    audit.row({"token": token, "to": h.to, "outcome": outcome.success,
               "rep_delta": delta})

function watchdog_for_open_handoffs():
    for token, h in open_handoffs.items():
        if now() - h.at > HANDOFF_DEADLINE:
            rep.update(agent=h.to, delta=-3, decay=DECAY_RATE)
            tracer.emit("handoff.deadline_missed", token=token)

# Why this works: ranking by reputation makes the swarm self-improving — peers
# who complete handoffs reliably get picked first. The handoff token is the
# single artefact that ties initiation, completion, and the reputation update.
# Related: see `handoff`, `trust-and-reputation-routing`, `swarm`.

