function run_agent(node, task, depth=0):
    if depth >= MAX_DEPTH or node.is_leaf:
        return node.do_work(task)

    subtasks = node.decompose(task)            # manager LLM call
    if len(subtasks) > MAX_BREADTH:
        subtasks = subtasks[:MAX_BREADTH]

    children_results = []
    for sub in subtasks:
        child = pick_child(node.children, sub.role)
        result = run_agent(child, sub.task, depth + 1)
        children_results.append(result)

    return node.synthesise(task, children_results)   # manager aggregates

