# Coordination seam: goal-decomposition produces subtasks WITH budget shares;
# the budget propagates down the tree and exhausting it at any node short-circuits.

class Budget:
    steps_remaining: int

function split_budget(parent_budget, n_children, fairness="proportional"):
    if fairness == "proportional":
        share = parent_budget.steps_remaining // n_children
        return [Budget(steps_remaining=share) for _ in range(n_children)]
    return [Budget(steps_remaining=parent_budget.steps_remaining // n_children)] * n_children

function run_agent(node, task, depth=0, budget=Budget(steps_remaining=TOTAL_STEPS)):
    if budget.steps_remaining <= 0:
        return Result(ok=False, error="budget exhausted at depth " + str(depth))

    if depth >= MAX_DEPTH or node.is_leaf:
        budget.steps_remaining -= 1
        return node.do_work(task)

    # goal-decomposition: the manager LLM call IS the decomposer
    subtasks = node.decompose_with_subgoals(task)            # [{role, subgoal, cost_est}]
    if len(subtasks) > MAX_BREADTH:
        subtasks = top_k_by_estimated_value(subtasks, MAX_BREADTH)

    child_budgets = split_budget(budget, len(subtasks),
                                  fairness="weighted_by_cost_est")
    children_results = []
    for sub, child_b in zip(subtasks, child_budgets):
        child = pick_child(node.children, sub.role)
        result = run_agent(child, sub.subgoal, depth + 1, child_b)
        children_results.append(result)
        # Unused budget RETURNS to the parent's pool
        budget.steps_remaining += child_b.steps_remaining

    return node.synthesise(task, children_results)

