# Coordination seam: the partition step is a pure map; workers emit typed
# outputs; the aggregator is a typed reduce — the whole thing reads as map/reduce
# with a NAMED aggregator role.

class WorkerOut:
    sub_task_id: str
    value:       Any
    confidence:  float

function map_step(task) -> list[SubTask]:
    # Deterministic partition — pure function, no LLM in the path
    return deterministic_partition(task, n=N_WORKERS)

function worker_fn(sub_task: SubTask) -> WorkerOut:
    raw = worker.run(sub_task, response_schema=WORKER_SCHEMA)
    WORKER_SCHEMA.validate(raw)                          # structured-output gate
    return WorkerOut(sub_task_id=sub_task.id, value=raw.value,
                     confidence=raw.confidence)

function reduce_step(outs: list[WorkerOut]) -> Aggregated:
    # The aggregator is a NAMED role implementing the reduce
    return aggregator.run(
        inputs={"outs": outs},
        policy={"on_conflict": "prefer_higher_confidence",
                "on_overlap":  "deduplicate"},
        response_schema=AGGREGATED_SCHEMA,
    )

function fan_out_gather(task):
    sub_tasks = map_step(task)
    worker_outs = parallel_map(worker_fn, sub_tasks)     # map
    return reduce_step(worker_outs)                       # reduce (named aggregator)

# Why this works: composing fan-out/gather with map-reduce and structured-output
# gives the whole pipeline a typed shape (SubTask -> WorkerOut -> Aggregated),
# so each stage is independently testable and the aggregator's reconciliation
# policy is the only LLM-shaped step.
# Related: see `map-reduce`, `structured-output`, `parallelization`.

# Production triad pipeline: each role timeout-bounded, arbiter verdicts are
# signed, human gates record reviewer identity, FAIL escalates to a named owner.
# Audit per handoff: each stage writes {stage, verdict, creator, critic, arbiter, reviewer}.

stages   = ["requirements", "design", "implementation", "verification", "release"]
