function role_call(role, fn, *args):
    try:
        with timeout(ROLE_TIMEOUT_MS[role]):
            return fn(*args)
    catch TimeoutError:
        tracer.emit("triad.role_timeout", role=role)
        return None

function triad_stage(stage_name, input_artifact):
    creator = Agent(prompt=CREATOR_PROMPTS[stage_name])
    critic  = Agent(prompt=CRITIC_PROMPTS[stage_name])
    arbiter = Agent(prompt=ARBITER_PROMPTS[stage_name])

    artefact = role_call("creator", creator.produce, input_artifact)
    if artefact is None:
        return None, Verdict("FAIL", reason="creator timeout")

    flaws = role_call("critic", critic.review, artefact, input_artifact)
    if flaws is None:
        flaws = []                                          # missing checker -> caution
        tracer.emit("triad.missing_checker", stage=stage_name)

    decision = role_call("arbiter", arbiter.decide,
                         artefact=artefact, flaws=flaws, input=input_artifact)
    if decision is None:
        return artefact, Verdict("FAIL", reason="arbiter timeout")

    assert decision.verdict in {"PASS", "FAIL", "PARTIAL"}
    decision.sig = sign(decision, arbiter_key())            # binding
    ledger.append({"stage": stage_name, "verdict": decision.verdict,
                   "creator_hash": hash(artefact),
                   "critic_hash":  hash(flaws),
                   "arbiter_sig":  decision.sig})
    return artefact, decision

HUMAN_GATES = {"requirements_validation": before("design"),
               "readiness_review":        before("implementation"),
               "deployment_approval":     before("release"),
               "production_confirmation": after("release")}
OWNERS = {"requirements": pm_owner, "design": arch_owner,
          "implementation": tech_lead, "verification": qa_owner,
          "release": ops_owner}

function human_gate(gate_name, artefact):
    reviewer, decision = human_gate_ui.await_decision(gate_name, artefact)
    ledger.append({"gate": gate_name, "reviewer": reviewer.id,
                   "decision": decision, "at": now()})
    if decision != "APPROVE":
        return escalate(gate_name, artefact, reviewer)

function run_pipeline(initial_input):
    artefact = initial_input
    for stage in stages:
        if stage in HUMAN_GATES.entry_points():
            human_gate(HUMAN_GATES.named_before(stage), artefact)
        artefact, decision = triad_stage(stage, artefact)
        if decision.verdict == "FAIL":
            notify_owner(OWNERS[stage], stage, artefact, decision)
            return escalate(stage, artefact, decision)
    human_gate("production_confirmation", artefact)
    return artefact

# Why this works: signed arbiter verdicts make the binding decision tamper-evident,
# per-role timeouts contain hung agents, and named owners per stage convert a
# FAIL into a concrete next-action instead of a dangling alert.
# Related: see `policy-gated-agent-action`, `approval-queue`, `supervisor-plus-gate`.

# Inference loop (the conductor has already been RL-trained)
function conductor_run(task, depth=0):
    history = [task]
    for step in 1..STEP_BUDGET:
        sub_task, worker_id = conductor.policy(history)   # small RL model

        if worker_id == "FINAL":
            return conductor.finalise(history)

        if worker_id == "CONDUCTOR" and depth < MAX_RECURSION:
            output = conductor_run(sub_task, depth + 1)   # self as worker
        else:
            output = WORKER_POOL[worker_id].run(sub_task)

        history.append({"sub_task": sub_task,
                        "worker":   worker_id,
                        "output":   output})

    return conductor.finalise(history)

