# Production scatter-gather-saga: idempotent operations, signed saga log,
# compensation retries, and a dead-letter queue for ops that need a human.
# Audit per handoff: each worker do/compensate writes {saga_id, worker, op_key, ok}.

class SagaWorker:
    name: str
    function do_action(self, sub_task, op_key) -> Result:    # idempotent on op_key
        ...
    function compensate_action(self, op_key) -> Result:       # idempotent on op_key
        ...

saga_log = AppendOnlyLog(sign_with=PRIVATE_KEY)
dlq      = DeadLetterQueue(name="saga_compensation")
workers  = [SagaWorker("reserve_inventory"), SagaWorker("charge_card"),
            SagaWorker("book_shipping"),    SagaWorker("send_confirmation")]

function try_run(worker, sub_task, op_key):
    backoff = 200
    for attempt in 1..MAX_DO_RETRIES:
        try:
            with timeout(WORKER_TIMEOUT_MS):
                r = worker.do_action(sub_task, op_key)
            saga_log.append({"saga": op_key.saga_id, "worker": worker.name,
                             "op_key": op_key, "event": "do_ok", "attempt": attempt})
            return Ok(r)
        catch TransientError as e:
            sleep(jitter(backoff, backoff * 2)); backoff *= 2
        catch FatalError as e:
            saga_log.append({"saga": op_key.saga_id, "worker": worker.name,
                             "event": "do_fail_fatal", "err": str(e)})
            return Err(e)
    return Err("do_action exhausted retries")

function compensate(worker, op_key):
    backoff = 500
    for attempt in 1..MAX_COMPENSATE_RETRIES:
        try:
            with timeout(COMP_TIMEOUT_MS):
                worker.compensate_action(op_key)
            saga_log.append({"saga": op_key.saga_id, "worker": worker.name,
                             "event": "compensate_ok"})
            return Ok(None)
        catch CompensationError as e:
            sleep(jitter(backoff, backoff * 2)); backoff *= 2
    # Could not undo — escalate to dead-letter queue for human recovery
    dlq.enqueue({"saga": op_key.saga_id, "worker": worker.name,
                 "op_key": op_key, "reason": "compensation exhausted"})
    return Err("compensation -> DLQ")

function scatter_gather_saga(task):
    saga_id   = new_id()
    sub_tasks = partition(task, n=len(workers))
    op_keys   = [OpKey(saga_id=saga_id, idem=stable_hash(sub)) for sub in sub_tasks]

    pending  = parallel_map(lambda triple: try_run(*triple),
                            zip(workers, sub_tasks, op_keys))
    committed, failed = [], None
    for w, ok_key, out in zip(workers, op_keys, pending):
        if out.is_ok: committed.append((w, ok_key, out.value))
        else: failed = (w, out.error); break

    if failed is None:
        return Ok(aggregator.merge([v for _, _, v in committed]))

    for w, ok_key, _ in reversed(committed):
        compensate(w, ok_key)
    return Err("saga aborted", failed_on=failed[0].name)

# Why this works: idempotent op_keys make safe retries possible; signed saga log
# is a tamper-evident recovery record; the dead-letter queue means a stuck
# compensation surfaces as a human-actionable ticket instead of silent drift.
# Related: see `compensating-action`, `parallelization`.

# Coordination seam: writes to the world-model raise structured events;
# event-driven-agents wake on the events; reads go through the world-model tool.

world_model = WorldModel(schemas={"todo": TodoSchema, "in_flight": InFlightSchema,
                                  "done": DoneSchema})
event_bus   = Bus()

# Stigmergy writes become EVENTS too — for event-driven-agent subscribers
function write_trace(key, value, ttl):
    world_model.write(key, value, ttl=ttl)
    event_bus.publish(f"trace.{key}", value)

# Agents have BOTH:
#   (a) read access via the world-model TOOL (pull),
#   (b) wake-up via event-driven subscriptions (push).
class WorldModelTool:
    function read(self, panel, filter):
        return world_model.read(panel, filter=filter)
    function written_since(self, panel, ts):
        return world_model.diff(panel, since=ts)

function event_driven_agent_loop(agent):
    agent.tools.append(WorldModelTool())                 # world-model-as-tool

    for event in event_bus.subscribe(agent.subscriptions):
        # event-driven-agent: wake only when something relevant happened
        decision = agent.decide(event=event, world=WorldModelTool())
        if decision.kind == "act":
            outcome = decision.execute()
            write_trace("done",
                        {"task": event.payload.task_id, "by": agent.id,
                         "result": outcome},
                        ttl=DONE_TTL_MS)

# Producer agents WRITE traces; consumers wake on them; no peer addressing.
for a in [parser, planner, executor, observer]:
    spawn(event_driven_agent_loop(a))

# Why this works: exposing the stigmergic environment as world-model-as-tool
# gives agents a typed read surface; raising events on every write turns the
# environment into a wake-up source for event-driven-agents — so coordination
# is both pull (read traces) and push (wake on trace) without direct messaging.
# Related: see `world-model-as-tool`, `event-driven-agent`, `blackboard`.

function sub_agent(task, tools, max_steps):
    # fresh context: no parent transcript leaks in
    messages = [system_prompt_for(task)]
    for step in 1..max_steps:
        reply = llm.generate(messages=messages, tools=tools)
        messages.append(reply)
        if not reply.tool_calls:
            return Result(ok=True, value=reply.content)
        for call in reply.tool_calls:
            messages.append(tool_result(call.id, dispatch(call, tools)))
    return Result(ok=False, error="step budget exhausted")

function parent():
    # parent sees only the structured return; no intermediate turns
    findings = sub_agent(
        task="audit auth module for security issues",
        tools=[Read, Grep, Glob],            # restricted palette
        max_steps=20,
    )
    return summarise(findings)

